import org.junit.jupiter.api.Test;

class DefaultCostModelCrossJoinPenaltyTest {

	@Test
	void crossJoinScoresHigherThanConnectedJoinWhenEstimatesAreEqual() {
		DefaultCostModel costModel = new DefaultCostModel();
		JoinOptimizationContext context = new JoinOptimizationContext(new EvaluationStatistics(),
				new EmptyTripleSource(),
				null, EmptyBindingSet.getInstance(), Set.of(), JoinEngineConfig.defaults(), OptimizationTraceSink.NOOP,
				BanditPolicy.noop(), new ConstantEstimator(), costModel);

		TupleExpr connectedJoin = new Join(statement("s", "o", "p1", "urn:p1"), statement("o", "x", "p2", "urn:p2"));
		TupleExpr crossJoin = new Join(statement("s", "o", "p1", "urn:p1"), statement("a", "b", "p3", "urn:p3"));

		Cost connectedCost = costModel.cost(connectedJoin, context);
		Cost crossJoinCost = costModel.cost(crossJoin, context);

		assertThat(crossJoinCost.getScore()).isGreaterThan(connectedCost.getScore());
	}

	private StatementPattern statement(String subjectVar, String objectVar, String predicateVar, String predicateIri) {
		Var subject = new Var(subjectVar);
		Var predicate = new Var(predicateVar, SimpleValueFactory.getInstance().createIRI(predicateIri));
		Var object = new Var(objectVar);
		return new StatementPattern(subject, predicate, object);
	}

	private static final class ConstantEstimator implements UncertaintyAwareEstimator {

		@Override
		public Estimate estimateRows(TupleExpr expr, JoinOptimizationContext ctx) {
			return new Estimate(10.0d, 0.20d, "TEST", Map.of("kind", expr.getClass().getSimpleName()));
		}
	}
}
